const headers = $input.first().json.headers;
const token = headers.authorization || '';

if (token !== `Bearer ${$env.API_BEARER_TOKEN}`) {
  throw new Error('401 Unauthorized: Invalid Bearer Token');
}

// We would extract user_id from JWT here. For now, we mock reading the user_id from the header or use a default.
const userId = headers['x-user-id'] || '11111111-1111-1111-1111-111111111111';

return [{ json: { user_id: userId } }];

const data = $input.first()?.json || {};
return [{
  json: {
    status: 'success',
    data: {
      total_jobs_found: data.total_jobs_found || 0,
      high_priority_jobs: data.high_priority_jobs || 0,
      total_applications: data.total_applications || 0,
      interview_invitations: data.interview_invitations || 0,
      applications_ready: data.applications_ready || 0,
      avg_ats_score: data.avg_ats_score || 0,
      success_rate: data.success_rate || 0
    }
  }
}];
